boolean  canPackingslipBeUpdated(DocumentStatus _documentStatus)
{
    boolean  ok = next canPackingslipBeUpdated(_documentStatus);

    if(ok)
    {
        ETGACFParameters acfParameters = ETGACFParameters::find();
        if(acfParameters.EnableSOWorkflow == NoYes::Yes && this.salesTable.ETGWorkflowStatus != VersioningDocumentState::Approved)
        {
            ok = checkFailed(strFmt("Packing slip can not be generated beacuse sales order %1 is not approved", this.salesTable.SalesId));
        }
    }

    return ok;
}

boolean  canPickingListBeRegistrated(boolean _mayBeRegistrated)
{
    boolean ok = next canPickingListBeRegistrated(_mayBeRegistrated);

    if(ok)
    {
        ETGACFParameters acfParameters = ETGACFParameters::find();
        if(acfParameters.EnableSOWorkflow == NoYes::Yes && this.salesTable.ETGWorkflowStatus != VersioningDocumentState::Approved)
        {
            ok = checkFailed(strFmt("Picking list can not be generated beacuse sales order %1 is not approved", this.salesTable.SalesId));
        }
    }

    return ok;
}
